/**
 * Test your API Key to see if it's valid.
 * @summary Validate Key
 */
export const authenticationValidateKey = (
    
 options?: SecondParameter<typeof tmdbFetch>,signal?: AbortSignal
) => {
      
      
      return tmdbFetch<AuthenticationValidateKey200>(
      {url: `/3/authentication`, method: 'GET', signal
    },
      options);
    }
  



export const getAuthenticationValidateKeyQueryKey = () => {
    return [
    `/3/authentication`
    ] as const;
    }

    
export const getAuthenticationValidateKeyQueryOptions = <TData = Awaited<ReturnType<typeof authenticationValidateKey>>, TError = AuthenticationValidateKey401>( options?: { query?:Partial<UseQueryOptions<Awaited<ReturnType<typeof authenticationValidateKey>>, TError, TData>>, request?: SecondParameter<typeof tmdbFetch>}
) => {

const {query: queryOptions, request: requestOptions} = options ?? {};

  const queryKey =  queryOptions?.queryKey ?? getAuthenticationValidateKeyQueryKey();

  

    const queryFn: QueryFunction<Awaited<ReturnType<typeof authenticationValidateKey>>> = ({ signal }) => authenticationValidateKey(requestOptions, signal);

      

      

   return  { queryKey, queryFn, ...queryOptions} as UseQueryOptions<Awaited<ReturnType<typeof authenticationValidateKey>>, TError, TData> & { queryKey: DataTag<QueryKey, TData, TError> }
}

